// src/pages/SellerDashboard.js
import React, { useState } from "react";

function SellerDashboard() {
  const [products, setProducts] = useState([]);
  const [form, setForm] = useState({
    name: "",
    description: "",
    category: "Earphone",
    price: "",
    offerPrice: "",
    image: "",
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setProducts([...products, form]);
    setForm({
      name: "",
      description: "",
      category: "Earphone",
      price: "",
      offerPrice: "",
      image: "",
    });
  };

  return (
    <div className="flex h-screen">
      {/* Sidebar */}
      <aside className="w-64 bg-gray-100 border-r p-4 space-y-6">
        <h1 className="text-2xl font-bold text-orange-600">QuickCart</h1>
        <nav className="flex flex-col space-y-4">
          <button className="text-left font-medium text-orange-600">
            ➕ Add Product
          </button>
          <button className="text-left">📦 Product List</button>
          <button className="text-left">📝 Orders</button>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-6">
        <h2 className="text-xl font-bold mb-4">Add Product</h2>

        {/* Product Form */}
        <form
          onSubmit={handleSubmit}
          className="grid grid-cols-2 gap-6 bg-white p-6 rounded-lg shadow"
        >
          {/* Uploads */}
          <div className="col-span-2 flex gap-4">
            {[1, 2, 3].map((i) => (
              <div
                key={i}
                className="w-24 h-24 flex items-center justify-center border-2 border-dashed rounded cursor-pointer"
              >
                <span className="text-gray-400">Upload</span>
              </div>
            ))}
          </div>

          {/* Product Name */}
          <div className="col-span-2">
            <label className="block text-sm font-medium mb-1">Product Name</label>
            <input
              type="text"
              name="name"
              value={form.name}
              onChange={handleChange}
              className="w-full border p-2 rounded"
              placeholder="Type here"
              required
            />
          </div>

          {/* Product Description */}
          <div className="col-span-2">
            <label className="block text-sm font-medium mb-1">Product Description</label>
            <textarea
              name="description"
              value={form.description}
              onChange={handleChange}
              className="w-full border p-2 rounded"
              placeholder="Type here"
              rows="3"
            ></textarea>
          </div>

          {/* Category */}
          <div>
            <label className="block text-sm font-medium mb-1">Category</label>
            <select
              name="category"
              value={form.category}
              onChange={handleChange}
              className="w-full border p-2 rounded"
            >
              <option>Earphone</option>
              <option>Smartphone</option>
              <option>Laptop</option>
              <option>Smartwatch</option>
              <option>Other</option>
            </select>
          </div>

          {/* Price */}
          <div>
            <label className="block text-sm font-medium mb-1">Product Price</label>
            <input
              type="number"
              name="price"
              value={form.price}
              onChange={handleChange}
              className="w-full border p-2 rounded"
              placeholder="0"
              required
            />
          </div>

          {/* Offer Price */}
          <div>
            <label className="block text-sm font-medium mb-1">Offer Price</label>
            <input
              type="number"
              name="offerPrice"
              value={form.offerPrice}
              onChange={handleChange}
              className="w-full border p-2 rounded"
              placeholder="0"
            />
          </div>

          {/* Add Button */}
          <div className="col-span-2">
            <button
              type="submit"
              className="bg-orange-600 text-white px-6 py-2 rounded font-semibold"
            >
              ADD
            </button>
          </div>
        </form>

        {/* Listed Products */}
        <h3 className="text-lg font-semibold mt-8 mb-4">Your Listed Items</h3>
        <div className="grid grid-cols-3 gap-4">
          {products.map((p, idx) => (
            <div key={idx} className="border p-4 rounded shadow">
              <h4 className="font-semibold">{p.name}</h4>
              <p className="text-sm text-gray-600">{p.description}</p>
              <p>Category: {p.category}</p>
              <p>Price: ₹{p.price}</p>
              {p.offerPrice && <p>Offer: ₹{p.offerPrice}</p>}
            </div>
          ))}
        </div>
      </main>
    </div>
  );
}

export default SellerDashboard;
